const crypto = require('crypto');
function cleanDate(value = "") {
    if (value == "") {
        return "";
    }
    return new Date(value.replace("12:00:00 AM", "").trim()).toISOString().split('T')[0];
}

// Source - https://stackoverflow.com/a/48161723
async function sha256(message) {
    // encode as UTF-8
    const msgBuffer = new TextEncoder().encode(message);   
    // hash the message
    const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);

    // convert ArrayBuffer to Array
    const hashArray = Array.from(new Uint8Array(hashBuffer));

    // convert bytes to hex string                  
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    return hashHex;
}

const chunkArray = (arr, size) => 
  Array.from({ length: Math.ceil(arr.length / size) }, (v, i) =>
    arr.slice(i * size, i * size + size)
  );


const lines = $input.item.json.text
    .split(/\r?\n/)
    .map(line => line.trim())
    .filter(Boolean);

const people = [];
const addressDates = [];
const appDates = [];

let i = 0;

while (i < lines.length) {
    const line = lines[i];

    if (line.startsWith("Last Name First Name DOB SSN")) {
        i++;

        while (i < lines.length && !lines[i].startsWith("City State Zip")) {
            const l = lines[i];

            if (
                l.startsWith("Hire date NCHC-CrediForce") ||
                l.startsWith("Date:") ||
                l.startsWith("Page ")
            ) {
                i++;
                continue;
            }

            const m = l.match(
                /^(.*?)\s+(\d{2}\/\d{2}\/\d{4})\s+(\d{3}-\d{2}-\d{4})\s+(.*)$/
            );

            if (m) {
                const nameTokens = m[1].trim().split(/\s+/);

                people.push({
                    "Last_Name": nameTokens[0] || "",
                    "First_Name": nameTokens.slice(1).join(" "),
                    DOB: cleanDate(m[2]),
                    SSN: m[3].replaceAll('-', ''),
                    "Street_1": m[4].trim(),
                    "Street_2": "",
                    "External_Id":await sha256(m[3].replaceAll('-', '') + $('start').item.json.account_id),
                  "Account":$('start').item.json.account_id,
                  "Name":nameTokens.slice(1).join(" ") + ' ' + nameTokens[0] || "",
                });
            }

            i++;
        }

        continue;
    }

    if (line.startsWith("City State Zip")) {
        i++;

        while (
            i < lines.length &&
            !lines[i].startsWith("Application Date Last Work Date")
        ) {
            const l = lines[i];

            if (
                l.startsWith("Hire date NCHC-CrediForce") ||
                l.startsWith("Date:") ||
                l.startsWith("Page ")
            ) {
                i++;
                continue;
            }

            const m = l.match(/^(.*?)\s+([A-Z]{2})\s+(\d{5})(?:\s+(.*))?$/);

            if (m) {
                const dates = (m[4] || "").match(/\d{1,2}\/\d{1,2}\/\d{4}/g) || [];

                addressDates.push({
                    City: m[1].trim(),
                    State: m[2],
                    Zip: m[3],
                    "First Work Date": cleanDate(dates[0] || ""),
                    "Rehire_Date": cleanDate(dates[1] || ""),
                    "Hire_Date": cleanDate(dates[2] || "")
                });
            }

            i++;
        }

        continue;
    }

    if (line.startsWith("Application Date Last Work Date")) {
        i++;

        while (
            i < lines.length &&
            !lines[i].startsWith("Last Name First Name DOB SSN")
        ) {
            const l = lines[i];

            if (
                l.startsWith("Hire date NCHC-CrediForce") ||
                l.startsWith("Date:") ||
                l.startsWith("Page ")
            ) {
                i++;
                continue;
            }

            const dates = l.match(/\d{1,2}\/\d{1,2}\/\d{4}/g) || [];

            if (dates.length) {
                appDates.push({
                    "Application_Date": cleanDate(dates[0] || ""),
                    "Last_Work_Date": cleanDate(dates[1] || "")
                });
            }

            i++;
        }

        continue;
    }

    i++;
}

const rowCount = Math.min(people.length, addressDates.length, appDates.length);

const rows = [];

for (let idx = 0; idx < rowCount; idx++) {
    rows.push({
        ...people[idx],
        ...addressDates[idx],
        ...appDates[idx]
    });
}



return chunkArray(rows,100).map(o=>{
  console.log(o);
  return {
    json:{
      data:o
    }
  }
})
